// src/utils/idbCleanup.js
init_build();
var DB_NAME = "chantilink-db";
var DB_VERSION = 2;
async function cleanupIndexedDB() {
  try {
    console.log("\u{1F9F9} [IDB Cleanup] D\xE9marrage du nettoyage...");
    const db = await openDB(DB_NAME, DB_VERSION);
    const stores = ["posts", "profile-posts", "users", "stories"];
    const sevenDaysAgo = Date.now() - 7 * 24 * 60 * 60 * 1e3;
    for (const storeName of stores) {
      if (db.objectStoreNames.contains(storeName)) {
        const tx = db.transaction(storeName, "readwrite");
        const store = tx.objectStore(storeName);
        const allKeys = await store.getAllKeys();
        let deletedCount = 0;
        for (const key of allKeys) {
          const item = await store.get(key);
          if (item?.timestamp && item.timestamp < sevenDaysAgo) {
            await store.delete(key);
            deletedCount++;
          }
        }
        await tx.done;
        console.log(`\u2705 [IDB Cleanup] ${storeName}: ${deletedCount} entr\xE9es supprim\xE9es`);
      }
    }
    const limits = {
      "posts": 100,
      "profile-posts": 50,
      "users": 50,
      "stories": 20
    };
    for (const [storeName, limit] of Object.entries(limits)) {
      if (db.objectStoreNames.contains(storeName)) {
        const tx = db.transaction(storeName, "readwrite");
        const store = tx.objectStore(storeName);
        const allKeys = await store.getAllKeys();
        if (allKeys.length > limit) {
          const toDelete = allKeys.slice(0, allKeys.length - limit);
          for (const key of toDelete) {
            await store.delete(key);
          }
          console.log(`\u2705 [IDB Cleanup] ${storeName}: ${toDelete.length} entr\xE9es supprim\xE9es (limite: ${limit})`);
        }
        await tx.done;
      }
    }
    db.close();
    console.log("\u2705 [IDB Cleanup] Nettoyage termin\xE9");
    return true;
  } catch (err) {
    console.error("\u274C [IDB Cleanup] Erreur:", err);
    return false;
  }
}
async function resetIndexedDB() {
  try {
    console.log("\u{1F525} [IDB Reset] R\xE9initialisation compl\xE8te...");
    const databases = await indexedDB.databases();
    for (const dbInfo of databases) {
      if (dbInfo.name === DB_NAME) {
        await new Promise((resolve, reject) => {
          const request = indexedDB.deleteDatabase(DB_NAME);
          request.onsuccess = () => {
            console.log("\u2705 [IDB Reset] Base supprim\xE9e");
            resolve();
          };
          request.onerror = () => reject(request.error);
          request.onblocked = () => {
            console.warn("\u26A0\uFE0F [IDB Reset] Suppression bloqu\xE9e, r\xE9essai...");
            setTimeout(resolve, 1e3);
          };
        });
      }
    }
    await openDB(DB_NAME, DB_VERSION, {
      upgrade(db) {
        const stores = ["posts", "profile-posts", "users", "stories"];
        stores.forEach((name) => {
          if (!db.objectStoreNames.contains(name)) {
            db.createObjectStore(name);
          }
        });
      }
    });
    console.log("\u2705 [IDB Reset] Base recr\xE9\xE9e");
    return true;
  } catch (err) {
    console.error("\u274C [IDB Reset] Erreur:", err);
    return false;
  }
}
async function checkStorageQuota() {
  try {
    if ("storage" in navigator && "estimate" in navigator.storage) {
      const estimate = await navigator.storage.estimate();
      const usage = estimate.usage || 0;
      const quota = estimate.quota || 0;
      const percentUsed = usage / quota * 100;
      console.log("\u{1F4CA} [Storage] Usage:", {
        used: `${(usage / 1024 / 1024).toFixed(2)} MB`,
        total: `${(quota / 1024 / 1024).toFixed(2)} MB`,
        percent: `${percentUsed.toFixed(1)}%`
      });
      if (percentUsed > 80) {
        console.warn("\u26A0\uFE0F [Storage] Quota > 80%, nettoyage automatique...");
        await cleanupIndexedDB();
      }
      return { usage, quota, percentUsed };
    }
    return null;
  } catch (err) {
    console.error("\u274C [Storage] Erreur v\xE9rification quota:", err);
    return null;
  }
}

